INSERT INTO bingo_task_pages (id, task_id, page_order, pointer_1, pointer_2, pointer_3, pointer_4, pointer_5, pointer_6) VALUES
  ('579e0aab-8309-4265-8993-93052672a826', '41f0f982-b6b9-49be-9d3b-705a94d95ee5', 0, 'A symbol of power stands where history and royalty meet.', 'Not a sword, not a spear, but a traditional weapon known for its wavy form.', 'It stands tall, far larger than what a warrior could carry,', 'built to honour a moment of royal celebration.', 'Find this legendary blade to begin your mission.', NULL),
  ('b4ac16de-06c0-473b-94b6-87737a30ddea', '41f0f982-b6b9-49be-9d3b-705a94d95ee5', 1, 'This weapon is not just about size, but also about its design.', 'Look closely around the monument and discover what the unique metal pattern is called.', 'Find the nickname of the metal design used in the keris.', NULL, NULL, NULL),
  ('b221a5e8-3bca-44a9-a620-6d63c19a6b21', '41f0f982-b6b9-49be-9d3b-705a94d95ee5', 2, 'You’ve found the royal blade. Now prove your team was there.', 'Take a group photo with the monument.', NULL, NULL, NULL, NULL),
  ('90912276-1254-4ede-80b0-2a77a813a667', '41f0f982-b6b9-49be-9d3b-705a94d95ee5', 3, 'All team members must be in the photo.', 'If not everyone is present, be creative (example: video call, reflections, creative angles, or props).', 'The keris monument must be clearly visible', NULL, NULL, NULL),
  ('a3d98146-66ed-461f-9e92-0a85f6ffecd1', 'dd774681-2fd0-42b1-a35e-e43cde6325f0', 0, 'Your journey now brings you to a piece of Klang’s history.', 'Somewhere nearby is a historical railway plaque. Find it carefully and read the story it tells.', 'Identify the missing word by understanding the sentence context', 'Fill in the missing word. 1 word answer.', NULL, NULL),
  ('7abeef93-8226-47cb-91d3-7a95c97945a1', 'dd774681-2fd0-42b1-a35e-e43cde6325f0', 1, 'Locate the Klang Railway Station historical plaque.', 'Study the text carefully.', 'You will notice some words are missing (scratched out).', NULL, NULL, NULL),
  ('ea6e2427-b24e-4e19-812d-f704ac9a4c64', 'dd774681-2fd0-42b1-a35e-e43cde6325f0', 2, 'Once you find the missing word:', NULL, NULL, NULL, NULL, NULL),
  ('b1d4090a-8605-4c63-82f9-8b23e26cb96c', 'dd774681-2fd0-42b1-a35e-e43cde6325f0', 3, 'Go to the place that the word represents.', 'Take one full team group photo at that location.', 'Submit the photo for VERIFICATION', 'BE VERY SAFE', NULL, NULL),
  ('c5dbfdbe-daaf-4d70-8b7a-09bc08b11116', 'fc88e570-5961-4ebf-9c78-9322d30b70fb', 0, 'Not every journey follows the same direction.', 'In Klang, there is a road where traffic seems to go against what you expect.', 'Find the street where vehicles travel differently from the usual Malaysian driving pattern.', '• Locate this unique road', '• Find the street sign', '• Take a photo with at least 2 team members pointing at the road sign'),
  ('5a0c0289-06d1-4056-b41a-c138bfa8b367', 'c23bb698-d6bf-4143-bcd1-25a2917ffc4a', 0, 'Your next location is a royal green space in Klang,', 'where locals walk, jog, and relax.', 'Many paths lead inside, but only one holds the number you need.', NULL, NULL, NULL),
  ('40531443-9e68-49cd-8c0a-f8b4e14fddac', 'c23bb698-d6bf-4143-bcd1-25a2917ffc4a', 1, 'Find the entrance path that leads you up, your answer is halfway up. That number unlocks your next task. First step is the beginning', NULL, NULL, NULL, NULL, NULL),
  ('92be81dd-fda3-423f-96be-015366f50b28', 'c23bb698-d6bf-4143-bcd1-25a2917ffc4a', 2, 'You received a braille clue.', 'Find it within the park', NULL, NULL, NULL, NULL),
  ('20987f8c-38c4-4a2d-90be-1f85a6cd82dc', 'c23bb698-d6bf-4143-bcd1-25a2917ffc4a', 3, 'Decode the braille', 'Identify what it represents', 'Take a group photo with it but becareful of other teams', NULL, NULL, NULL),
  ('03ab05bb-1328-4000-aad5-aec4b2a00248', '019c2246-db2b-485b-b9e1-13070989da30', 0, 'Find the historic building whose exterior resembles the red and white stripes of the Malaysian flag (Jalur Gemilang).', 'What is this building?', NULL, NULL, NULL, NULL),
  ('90e0a84f-d2c3-4726-ba5b-77a85bde50ca', '019c2246-db2b-485b-b9e1-13070989da30', 1, 'When is it completed?', NULL, NULL, NULL, NULL, NULL),
  ('a747576e-e1c7-4fcc-b9a3-a9e8a37bd204', '019c2246-db2b-485b-b9e1-13070989da30', 2, 'Have at least 3 person taking photo with the Fire Station.', NULL, NULL, NULL, NULL, NULL),
  ('c9f50033-542d-465a-ace1-7c7206886d2c', 'deea43be-b6a4-4dd5-b4a3-91997c32a19a', 0, 'Long before modern cranes and containers, goods arriving in Klang were unloaded manually from wooden ships. Sailors and port workers carried sacks, crates, and supplies on their shoulders, working together to move cargo from the docks to land.', 'Your team must travel back in time and recreate this historical moment.', 'Find the ship-themed playground structure at Pangkalan Park. This structure represents Klang’s historical port activities and maritime trade heritage.', NULL, NULL, NULL),
  ('686617d8-7fab-41c5-8df7-9ddb488391a6', 'deea43be-b6a4-4dd5-b4a3-91997c32a19a', 1, 'Recreate a scene from the 1800s:', 'Take a team photo showing the action.', 'Use AI (Gemini or similar) to transform your photo:', 'Create an 1800s historical port feel', 'Submit the EDITED PHOTO', NULL),
  ('d9f0ca6d-10af-4e4f-8b07-7533274a1a6f', 'deea43be-b6a4-4dd5-b4a3-91997c32a19a', 2, 'Pretend to unload cargo from a ship', 'Carry “imaginary sacks” on shoulders', 'Form a human chain passing goods', 'Pose like dock workers directing cargo', 'Change colours to sepia or black & white', 'Add old-time atmosphere (fog / grain effect)'),
  ('7ee59095-e134-4bd4-bc47-0a8451d31e2f', 'deea43be-b6a4-4dd5-b4a3-91997c32a19a', 3, 'Make clothing look vintage if possible', NULL, NULL, NULL, NULL, NULL),
  ('bbf5549d-cd55-40d7-8529-e8b5510bacda', '90068a51-a8ee-4fa6-94de-ccc386f4dac5', 0, 'In the old streets of Klang, a group of birds watches from above.', 'They fly together, guiding those who pay attention.', 'Follow the 12 crows and they will lead you to a place that tells their story.', NULL, NULL, NULL),
  ('3957be92-4efb-4b57-b4b8-907d94804b9f', '0f370849-9f38-448a-9e6a-0921346d980d', 0, 'Proceed to Laman Seni.', 'Meet the Marshal', 'Collect 1 Chapteh from the resource table and find a suitable location for your team.', 'Your team must successfully complete 5 consecutive passes between 5 different people.', 'Take a video of your team successfully completing the Chapteh passes.', 'Make sure the video clearly shows:'),
  ('74df8bc0-b9a1-490a-bd7a-6433dfd46149', '0c4f0730-075e-40c1-b46d-4ed7f0e2d7d0', 0, 'A legendary bakery in Klang has been serving one of the town’s most recognisable layered desserts.', 'Located at shoplot 70 along a busy road, this family business has built its reputation one slice at a time.', 'What is the name of this famous shop to unclock your next clue.', NULL, NULL, NULL),
  ('ac6ad3e0-73ea-4531-b223-1ada2df10b91', '0c4f0730-075e-40c1-b46d-4ed7f0e2d7d0', 1, 'Level 2 – The Family Name', 'After completing your purchase, find out the owner''s Chinese surname.', 'What does his surname mean when translated into English?', NULL, NULL, NULL),
  ('1a943fe4-9452-4386-b677-187b3ba2671e', '0c4f0730-075e-40c1-b46d-4ed7f0e2d7d0', 2, '*Hint* His first name is Cheng', 'Be respectful if the place is busy', 'Do not force your way in', NULL, NULL, NULL),
  ('5cc71a32-f4ba-4259-a013-b5d5f9be6e47', '6c13f0e4-6f86-4e60-bbab-b31d03cbd430', 0, 'Hidden within Pasar Jawa is a shop that has stood the test of time. Look for Kak Liza at Pasar Jawa. The shelves are filled with traditional snacks and goods — but what you really seek is knowledge passed down through the years.', 'To earn the answer, your team must purchase any one item from the shop. Only then may you ask Kak Liza the questions.', 'Be respectful, be polite, and support the local business before asking your questions.', NULL, NULL, NULL),
  ('cbe20008-eda8-430a-a246-1a355eafa9ce', '6c13f0e4-6f86-4e60-bbab-b31d03cbd430', 1, 'How many generations has this family been running the business?', NULL, NULL, NULL, NULL, NULL),
  ('d4f7191b-8770-420b-9a4d-8cf57a0375db', '6c13f0e4-6f86-4e60-bbab-b31d03cbd430', 2, '2. How many years have they been operating here?', NULL, NULL, NULL, NULL, NULL),
  ('ba99c778-a6a3-4d87-9b57-6a27065ddaed', '6c13f0e4-6f86-4e60-bbab-b31d03cbd430', 3, 'Take a photo with Kak Liza or her colleagues!', NULL, NULL, NULL, NULL, NULL),
  ('8b505c20-6b4a-412d-be3b-c0cfe4206898', '4f08eb1d-ef81-4c9c-80b3-b680b986c974', 0, 'Along Jalan Raya Timur stands a building from 1916, still watching the town grow around it.', 'Inside, you’ll find something served in small portions, usually shared, steamed, and loved during tea time.', 'What bite-sized food are they selling here?', NULL, NULL, NULL),
  ('86eef348-bc9d-49dc-aa72-a1bb80324192', '4f08eb1d-ef81-4c9c-80b3-b680b986c974', 1, 'Take a photo of someone holding that food on their hands infront of the building.', 'Criteria,', '1. Must see the whole facade', '2. Food must be found in the menu (not necessarily bought)', '3. Be Creative', '4. Be safe and respectful'),
  ('6ccf1a10-2723-4e68-9176-54bb75c2b24b', 'ad5e3009-de99-41be-a2ab-2ff3be87c33f', 0, 'Your next clue brings you to a local favourite.', 'Head over to Chong Kok Kopitiam and complete this mission carefully.', 'After ordering, politely speak to the owner or staff.', 'Only after you have:', 'Shown good manners', 'They will reveal the answer.'),
  ('7a7b4401-e1ee-48c9-8fb2-4ef72e335cfa', 'ad5e3009-de99-41be-a2ab-2ff3be87c33f', 1, 'Enter respectfully – this is a real operating restaurant.', 'It will be a busy breakfast hour, so be patient and polite.', 'Only 2–3 participants may enter at one time.', 'The rest of the team must wait outside and must not crowd the shop.', 'Order one breakfast set (example: Roti Goyang, Hainan Roti, Bun Bakar, or similar).', 'You must finish your order before requesting the clue.'),
  ('8f39a4b1-6b9a-4e12-ace9-b8496dff1c7e', 'ad5e3009-de99-41be-a2ab-2ff3be87c33f', 2, 'Ordered', 'Eaten', NULL, NULL, NULL, NULL),
  ('9b0978e8-4dd7-4dbd-b5d0-73cb5610ebb0', 'eebaeb76-841d-44ab-bfbc-3fadd3e9a99b', 0, 'Step 1 – Inside Galeri Diraja Klang', 'Find a painting that represents the state you are standing in.', 'Look for a framed artwork showing the word SELANGOR formed by people.', 'Task 1', 'When was this artwork completed?', 'Month + Year'),
  ('cad4000a-62ab-4359-8920-fbdcd203fd28', 'eebaeb76-841d-44ab-bfbc-3fadd3e9a99b', 1, 'Study how the people in the artwork are forming the letters.', 'Letter shapes', 'You will need this for the next challenge.', NULL, NULL, NULL),
  ('55ed83d1-1020-486e-844d-5581131c7840', 'eebaeb76-841d-44ab-bfbc-3fadd3e9a99b', 2, 'Body positions', 'Spacing', NULL, NULL, NULL, NULL),
  ('2e828bc8-b1db-4664-96f8-d457e540f064', 'eebaeb76-841d-44ab-bfbc-3fadd3e9a99b', 3, 'Step 3 – Outside Action Challenge', 'Exit the gallery.', 'Recreate the SELANGOR pose using your team members.', NULL, NULL, NULL),
  ('2979acef-130a-44f1-bc48-00f1e1777ba1', 'eebaeb76-841d-44ab-bfbc-3fadd3e9a99b', 4, 'All members must form the word', 'One continuous formation (not separate groups)', 'Take a landscape photo', 'Minimum 1 photo submission', 'If you don''t have enough people, BE CREATIVE', NULL),
  ('408ff408-95b3-4fcf-a688-bb1208901e96', 'e42bd4f8-9fad-41e8-85a6-f1b17bc4aeee', 0, 'Before digital banking and e-wallets, a nation’s strength was reflected in its currency. Hidden within this gallery is a special coin minted to honour an important milestone in Malaysia’s financial history.', 'Find the commemorative coin celebrating the 30th anniversary of Bank Negara Malaysia.', NULL, NULL, NULL, NULL),
  ('36e92a0e-6beb-4ea8-95a0-21b8158dfe98', 'e42bd4f8-9fad-41e8-85a6-f1b17bc4aeee', 1, 'Some history is not written in books… it is minted in metal.', 'Find the commemorative coin celebrating the 30th anniversary of Bank Negara Malaysia.', 'This coin celebrates Bank Negara Malaysia from which year to which year?', 'YYYY – YYYY', NULL, NULL),
  ('48d69f18-c5c7-439f-b379-0e17e8b5a5f6', 'e42bd4f8-9fad-41e8-85a6-f1b17bc4aeee', 2, 'Knowledge alone is not enough — prove your discovery.', 'Coin must be clearly visible', NULL, NULL, NULL, NULL),
  ('83069d50-2ba0-4f7e-9814-79329e47ddb4', 'e42bd4f8-9fad-41e8-85a6-f1b17bc4aeee', 3, 'Take ONE group photo', 'Must include the coin', 'Must include at least 4 team members', 'No selfies without the coin visible', 'No zooming from far (must be near display)', 'All 4 faces must be visible'),
  ('7c6ea410-9073-46d6-a70d-b8da1e5f0b87', 'e42bd4f8-9fad-41e8-85a6-f1b17bc4aeee', 4, 'No blocking museum pathways', 'Becareful of your surroundings', 'Do NOT take VIDEO', NULL, NULL, NULL),
  ('9f88dd7f-c2c9-4f91-bba8-0314eb731f32', '8ca4dc9a-f892-42e3-9b01-28350ad72d32', 0, 'The Bugis prince from Luwu founded the Selangor Sultanate.', 'Generations later, one of his descendants became Malaysia’s 2nd Yang di-Pertuan Agong.', 'Find him in the Selangor royal lineage gallery and take a team photo pointing at his panel.', NULL, NULL, NULL),
  ('7196ad76-34f9-451e-be7b-51cf7e3702a2', 'eb9ec450-23af-4f5c-910f-097e6a804328', 0, 'Throughout the hunt, there are special Bonus Photo Targets hidden around town. These can be unique landmarks, unusual objects, or easily overlooked details most people walk past. Your team must identify the correct location or item based on the clue, travel there, and take a clear team photo as proof.', 'Tip: The best teams balance speed, observation, and strategy — sometimes the biggest points go to the teams willing to explore a little further.', NULL, NULL, NULL, NULL),
  ('a8bff722-69c1-4038-b09f-dc0f6755d01d', '620c9229-cc25-4e50-b40a-1e745709ad1a', 0, 'Throughout the hunt, there are special Bonus Photo Targets hidden around town. These can be unique landmarks, unusual objects, or easily overlooked details most people walk past. Your team must identify the correct location or item based on the clue, travel there, and take a clear team photo as proof.', 'Tip: The best teams balance speed, observation, and strategy — sometimes the biggest points go to the teams willing to explore a little further.', NULL, NULL, NULL, NULL),
  ('248902ac-4354-4604-a51d-0b9990e125d1', '28357602-b54e-434a-a01a-b4686ef51de3', 0, 'Throughout the hunt, there are special Bonus Photo Targets hidden around town. These can be unique landmarks, unusual objects, or easily overlooked details most people walk past. Your team must identify the correct location or item based on the clue, travel there, and take a clear team photo as proof.', 'Tip: The best teams balance speed, observation, and strategy — sometimes the biggest points go to the teams willing to explore a little further.', NULL, NULL, NULL, NULL),
  ('4909bec6-2862-4b68-a340-e2d51388ae89', 'ac1e3dfb-6d3a-4cad-8399-c658371865e1', 0, 'Throughout the hunt, there are special Bonus Photo Targets hidden around town. These can be unique landmarks, unusual objects, or easily overlooked details most people walk past. Your team must identify the correct location or item based on the clue, travel there, and take a clear team photo as proof.', 'Tip: The best teams balance speed, observation, and strategy — sometimes the biggest points go to the teams willing to explore a little further.', NULL, NULL, NULL, NULL),
  ('119aad82-ee73-4fa7-9bf3-036768887587', '63ef3241-9c36-4ab9-8802-b15e56ce6542', 0, 'Throughout the hunt, there are special Bonus Photo Targets hidden around town. These can be unique landmarks, unusual objects, or easily overlooked details most people walk past. Your team must identify the correct location or item based on the clue, travel there, and take a clear team photo as proof.', '*FYI* The deer may be different now', 'Tip: The best teams balance speed, observation, and strategy — sometimes the biggest points go to the teams willing to explore a little further.', NULL, NULL, NULL),
  ('733d3e37-91b9-440f-8936-452db58a7bef', 'e2aeb8fc-9ebc-4ad2-a07c-dfe97cf8090a', 0, 'Gather 18,000 steps as a team!', 'Use your pedometer, phone app to calculate your steps as a team.', 'Gather everyone''s result, take one photo of all the steps in each device and make sure the total is more than 18,000 steps!', NULL, NULL, NULL),
  ('c8d3a3b3-84a8-4201-a710-54d46ec59c44', '951ad600-1abd-4be7-9e0c-a91381032de7', 0, 'Achieve 50 push ups 50 sit ups 30 burpees Complete this task together as a team, accumulate!', NULL, NULL, NULL, NULL, NULL),
  ('c7d2336b-8d3b-429d-834f-bfb9aba895fb', '2641c858-cc1f-4a59-9402-0348602e9397', 0, 'Collect 1 Chapteh from the resource table and find a suitable location for your team.', 'Your team must successfully complete 5 consecutive passes between 5 different people.', 'Take a video of your team successfully completing the Chapteh passes.', 'Make sure the video clearly shows:', '• 5 successful passes', '• 5 different participants'),
  ('74690a56-c9c1-42bb-8be9-4a8dd87fdcd9', 'd6bd5956-c9e9-428a-a831-5099049af887', 0, 'Your team must gather all 10 listed items and present them in ONE unified group photo. Strategy, teamwork, and creativity will determine how fast you succeed.', '1. Red Shoe', '2. Wheel3. Ball4. Belt5. Umbrella6. White Cap7. Yellow Shirt8. Leaf (The size of your team''s biggest head)9. Soft Drink10. Toy', '😎 You may find, borrow, improvise, or creatively represent the items.', 'There are no limits to how you achieve this, only the final result matters.', 'Be resourceful. Be strategic. Be creative.'),
  ('05f4466d-47bf-4f1d-8b8e-c609cc02c115', '43bf7e3e-8fa0-4c7e-8957-03d409373c8a', 0, '📷 Find the 5 zoomed-in images shown on the next pages.', 'These photos are taken from locations around the venue.', 'Your Mission', 'Hunt for the exact location or object.', 'Submit all photos to the marshal.', '• All team members must appear in every photo.'),
  ('ddc60872-ab48-4ee0-85ae-5d030dd66a2c', '43bf7e3e-8fa0-4c7e-8957-03d409373c8a', 1, '😎 Identify where each zoomed image was taken.', '👥 Take a full team group photo with the correct place/item.', NULL, NULL, NULL, NULL),
  ('06379823-e2fc-43a8-9ab3-8b3f27bdbbc7', '63380862-7276-4413-9d9a-602a67f369ff', 0, 'The city is full of hidden signals. Your team must capture the colors that form the code.', 'Your team must collect photo evidence of 6 assigned colors.', '🔴 Red', '🔵 Blue', '🟡 Yellow', '🟢 Green'),
  ('35a5c562-2c48-48f9-ab48-2577f388f989', '63380862-7276-4413-9d9a-602a67f369ff', 1, 'Each color must have 4 different photos', 'Every photo must include at least 2 team members', 'Photos must clearly show the dominant color', 'No repeating the same object/location', 'Teams must split roles to complete faster', 'All photos must be combined into ONE collage'),
  ('9af4b1b2-df94-4d6c-8ed8-c6225fb9bae3', '41e95be0-2f3f-4476-9a3e-6e4e5a699494', 0, 'Find 10 different people wearing white shoes and take one group photo together as proof of completion.', 'Your full team must also be inside the same photo.', '• Must be 10 different people (no repeats).', '• Shoes must be mainly white (minor other colors allowed).', '• Team must ask respectfully — no forcing participation.', '• Photo must clearly show the shoes.'),
  ('eb4f3925-e300-46cb-b721-bf410adca8ac', '41e95be0-2f3f-4476-9a3e-6e4e5a699494', 1, 'Approach people politely and ask for their help.', 'Each person must be a different individual.', 'All 10 people must clearly show their white shoes in the photo.', NULL, NULL, NULL),
  ('d1757103-ba57-466e-8bc2-c8a6d85ac335', 'f9cb36d8-3d6b-4fac-b93b-ccd55512f6d0', 0, 'Somewhere in the area, a marshal is moving around quietly. He is not stationed at a fixed point, and you will need to rely on your observation and communication skills to locate him.', 'Submit the photo to complete this mission.', 'No photo editing allowed.', 'Correct marshal + correct plate number + group photo submission.', NULL, NULL),
  ('150144a1-9a8b-4f37-bbb1-408b40d9d804', 'f9cb36d8-3d6b-4fac-b93b-ccd55512f6d0', 1, 'Find the marshal who owns the vehicle with plate number AFW7825.', 'He will be roaming around the venue — ask other marshals or participants if needed.', 'Once you think you found the correct marshal, verify the car plate number with him.', 'Take a full team group photo with the marshal as proof.', 'You must confirm the correct marshal (wrong marshal = redo).', 'Entire team must appear in the photo.'),
  ('b23c11d0-2b9f-4df7-8ec9-c2db56cea2d7', 'f9cb36d8-3d6b-4fac-b93b-ccd55512f6d0', 2, 'Marshal’s face and at least one team member must be clearly visible.', NULL, NULL, NULL, NULL, NULL),
  ('f23181a1-5266-4aac-9597-827b94f7c117', '96a0e7a7-44ab-4ebc-a282-4416d83fd8ae', 0, 'The tower collapses.', 'Edit an animal on the chair stack using A.I.', 'Take a group photo with the final output!', NULL, NULL, NULL),
  ('f16661f8-00e2-4a9e-9db0-e679bff11bc9', '96a0e7a7-44ab-4ebc-a282-4416d83fd8ae', 1, 'Stacking turn – Each team member takes turns adding one chair at a time.', 'Chairs must be balanced carefully without disturbing the previous ones.', 'The process continues until:', 'The team reaches 18 chairs, or', NULL, NULL),
  ('70febd5e-daa2-4aa3-aef1-315ebc7f9503', '4c440e02-8cde-4e23-af27-35f76dea98f5', 0, 'Work together as a team using 1 Kendama.', 'Take turns attempting the moves and achieve 3 successful tricks as a team.', '• Use only 1 Kendama per team', '• Players must take turns', '• Complete this sequence:', 'Left cup → Right cup'),
  ('fc4f3cfb-4141-4ff6-ba07-2bc6ba0f67f3', '9b0f03b6-a21c-46b4-b513-6cd0c63db369', 0, 'Work together to reconstruct the Soma Cubes using teamwork, logic, and strategy.', '• Each team will receive 3 identical Soma cube puzzle sets', '• All puzzle pieces will be fully disassembled', '• Teams must reassemble the pieces into complete cubes', '• Team members may sort, pass, and assemble pieces collaboratively', '• Teams may decide their own strategy and roles'),
  ('82b10a19-36f6-4f39-a549-fb8d94489287', '9a5cdfee-4c0e-41f0-930f-25281d857da8', 0, '🔥 This is a competition task', '💥 Battle with a player from another team🤝 The first to win a Best of 3 wins⭐ Winner gets a token from the opponent❌ Only the team who initiated this challenge can mark this task as done.', NULL, NULL, NULL, NULL),
  ('62cc439c-b030-4c23-a394-532d72befd27', '4b998708-43a4-4391-8e9e-a179d880c30f', 0, 'Challenge by testing who can say AHH! the longest!', 'First to stop loses.', 'Select 3 members to fight!', '🏆 First team that reaches 3 members to win, WINS!', NULL, NULL),
  ('e6c27530-42a8-49ae-84bf-f4494917b281', 'eb13ea21-b5e5-46f2-b2d1-ce9b974c8460', 0, 'Find another team and challenge them by comparing your total number of tokens.', '• Both teams reveal their token count at the same time.', '• The team with more tokens wins the challenge.', '• Winning team collects 1 token from the losing team.', '• If the losing team has no tokens, no tokens are exchanged.', '• If both teams have the same number of tokens, it is a draw and both teams may challenge others.'),
  ('0ff05752-9099-40af-bd06-ff4c438d3712', 'a47ceb7d-b7c3-4b60-8f78-340ed13f4a02', 0, 'The tongue twister they must say is:', 'Betty bought a bit of butter but the butter was bitter, so Betty bought another butter to make the bitter butter better.', NULL, NULL, NULL, NULL),
  ('f41f6257-095c-424f-8a9e-996408852116', 'a47ceb7d-b7c3-4b60-8f78-340ed13f4a02', 1, 'Challenge another team to a tongue twister battle.', 'Each team can send maximum 3 players.', 'Both teams must say "ready" before starting.', 'They must say the tongue twister as fast and as accurately as possible.', 'The fastest and most accurate team wins.', 'The winner gets 1 token from the losing team.'),
  ('66fc2436-942c-4353-a527-ff9dc0fed504', 'a47ceb7d-b7c3-4b60-8f78-340ed13f4a02', 2, 'The task is completed for both teams once played.', 'You must record a video of the battle.', 'The players competing must be visible in the video.', '1 video per team is enough.', 'Teams cannot compete again with the same team in another RD game.', NULL),
  ('cde0f7ac-a514-4054-a0af-b545e2d0cdcb', '2ecd07ae-fc0b-4204-8c64-212f1a689ae8', 0, 'Celebrate teamwork by sharing a friendly high-five with another team to recognize a job well done. This is a bonding activity focused on sportsmanship and positive interaction rather than competition.', NULL, NULL, NULL, NULL, NULL),
  ('2b51cacf-c4f6-4249-a40b-7293cfb4b4ca', '2ecd07ae-fc0b-4204-8c64-212f1a689ae8', 1, 'This is not a competition task', 'Record one video of your team exchanging a high-five with another team', 'All team members must appear in the video', 'Only one submission per team is required', 'You cannot high-five the same team you competed with in other RD Games (and vice versa)', 'For Syariah-compliant participants, an air high-five is acceptable'),
  ('6fb7ed58-a3c0-4ef4-bed5-8e7c04ff0573', 'cadc29d0-d46a-4540-b075-50174f6c5649', 0, 'Swipe through the images below and recreate each formation using your team members’ bodies. Capture a photo that matches the original as closely as possible.', 'Mission: Copy the shape. Become the shape. Prove the match.', 'Show your photos to the marshal for verification before proceeding.', NULL, NULL, NULL),
  ('8050d8f8-af8e-4845-a4ce-513357f303c7', 'b673ebfe-e35b-40f9-b21b-d2c74fecd9fd', 0, 'Work together to guide 5 balls from Point A to Point B using the tarp and drop them into the bucket.', '• Everyone must hold the tarp at all times', '• Do not let the balls fall into the holes or off the tarp', '• If a ball drops, restart that ball', '• Bucket must stay on the floor', 'Record a video of your successful completion.'),
  ('3dd91b3e-683e-4a0b-8444-4f7d6c6542e6', 'c2d2a873-fd21-4811-8768-a649bb54e191', 0, 'Work together to successfully pass the ball around the circle and return it to the starting player without dropping it.', '• Form one complete circle with your team', '• Each participant holds one ball', '• Use RIGHT HAND ONLY', 'The EGG and balls must return to the original starting player', '• Right hand only'),
  ('11c7f60e-6109-4af4-b7c6-b89dedfadc91', 'c2d2a873-fd21-4811-8768-a649bb54e191', 1, 'All players prepare with the ball in their right hand', 'On the signal, everyone tosses to the person on their RIGHT', 'Continue until the ball completes one full round', NULL, NULL, NULL),
  ('e3f0b2de-8d98-4e4d-afe2-b705de7a9bc0', 'f827b9cc-b7fc-4d0e-984c-0bedde5ba7fc', 0, 'Objective', 'Work as a team of minimum 8 members to perform the 5 Water Bending moves correctly and in sequence.', 'Rules', 'All members must complete the moves together.', 'How (Execution)', 'Rise'),
  ('3f84a0d4-0c23-4c20-8b69-3d069c373aa8', 'f827b9cc-b7fc-4d0e-984c-0bedde5ba7fc', 1, 'All 5 moves must be performed in the correct order.', 'Minimum 8 members must participate.', 'One person must record the full sequence (can rotate).', 'Wide Stance', 'Scoop', 'Spin'),
  ('887733cc-a44a-4e40-bea6-2e9e2b5b6b02', 'f827b9cc-b7fc-4d0e-984c-0bedde5ba7fc', 2, 'Push', NULL, NULL, NULL, NULL, NULL),
  ('5d6b9148-dc1f-447f-a492-cfa32c5b16ed', '1a55f03e-c31b-453b-a988-587dfd55b81e', 0, 'Work together to create different shapes using only your bodies and your shadows. Position yourselves between the light source and the wall to form the correct silhouette.', 'Recreate the required shadow shapes using full team coordination and submit photo proof.', 'Completion of all required shadow shapes correctly.', 'How to Submit', 'Compile all your photos in 1 image and submit.', 'SHAPES'),
  ('53bcbe69-ea9d-4200-b5ee-d35213a47a75', '8cb0f7c0-88ef-4fd0-9b96-b8f438a382f9', 0, '"One Team. Many Dreams. One Photo."', 'Your team will use Gemini AI to transform a simple group photo into a global masterpiece. Every member must bring their favourite country into the picture — either as the background or as a creative object that represents it.', 'Show teamwork, creativity, and storytelling through AI editing.', 'Submit the edited photo to the marshal.', 'Examples of creative ideas:', 'NY skyline → USA'),
  ('c9092cf4-37fd-4e8d-b246-66ae8b27f18d', '8cb0f7c0-88ef-4fd0-9b96-b8f438a382f9', 1, 'Take ONE clear group photo (everyone must be visible).', 'Each team member states their favourite country.', 'Each country appears in the image (background OR object)', 'All faces remain clearly visible', 'The final image looks creative and fun', 'Eiffel Tower → France'),
  ('a929b80f-138a-4aaf-924c-af6df2246573', '8cb0f7c0-88ef-4fd0-9b96-b8f438a382f9', 2, 'Samurai sword → Japan', 'Pizza or Colosseum → Italy', 'Kangaroo → Australia', '✔ No removing teammates from the photo', NULL, NULL),
  ('c292f22d-a8e6-45a4-8a70-8cd42288ad77', 'e9d0edac-d1f9-438a-9a8a-27bb2158f7de', 0, '“Last Photo Before Impact”', '🎯 Objective', 'Your team must act out a dramatic scene where an asteroid is about to hit Earth. Strike your most creative survival, panic, or heroic poses. Take a group photo and enhance it using AI (Gemini or any AI editor) to add the asteroid, explosions, or dramatic sky effects.', NULL, NULL, NULL),
  ('c0c4790c-6592-4a92-b7e9-c88f6a161af3', 'e9d0edac-d1f9-438a-9a8a-27bb2158f7de', 1, '1. Gather your full team (everyone must appear in the photo).', '😱 Panic mode', '🦸 Heroic sacrifice', '🧠 Scientist solving the crisis', '😂 Funny “end of the world” reaction', '3. Strike a dramatic pose together.'),
  ('a1245f67-ad9f-46cb-8fcb-9ef948e5e820', 'e9d0edac-d1f9-438a-9a8a-27bb2158f7de', 2, '4. Take 1 clear group photo.', 'Asteroid in the sky', 'Fire / smoke effects', 'Cracked ground or destruction', 'Dramatic lighting', NULL);
